// Days until due
if(empty(prop("Due Date")), "No due date",
  dateBetween(prop("Due Date"), now(), "days") + " days")

// Overdue check (returns boolean)
if(empty(prop("Due Date")), false,
  and(prop("Status") != "Done", prop("Due Date") < now()))

import os, time
from notion_client import Client

notion = Client(auth=os.environ["NOTION_TOKEN"])
SPRINT_PAGE_ID = os.environ["CURRENT_SPRINT_PAGE_ID"]

def assign_to_sprint(task_page_ids: list[str]):
    """Assign selected backlog tasks to current sprint.
    Call only after human approval of the sprint plan.
    """
    for page_id in task_page_ids:
        notion.pages.update(
            page_id=page_id,
            properties={
                "Sprint": {
                    "relation": [{"id": SPRINT_PAGE_ID}]
                }
            }
        )
        time.sleep(0.35)  # stay under 3 req/sec limit
